import { DEFAULT_BASIC_SHAPE_COLOR_TOKEN } from '../constants.js';

type CustomCategoricalColorObject = { [key: string]: string };

export const createCategoricalColorSchemeFromCustomColorObject = (
  colorPalette: CustomCategoricalColorObject,
  categories: string[],
): CustomCategoricalColorObject => {
  let obj = { ...colorPalette };

  categories.forEach((categoryName, index) => {
    if (!obj[categoryName]) {
      obj = {
        ...obj,
        [categoryName]: DEFAULT_BASIC_SHAPE_COLOR_TOKEN.Default,
      };
    }
  });

  return obj;
};
